@startuml
skinparam classAttributeIconSize 0
skinparam shadowing false
skinparam class {
  BackgroundColor #f7f7f7
  BorderColor #333333
  ArrowColor #333333
}

abstract class Display {
  +getColumns(): int
  +getRows(): int
  +getRowText(row: int): String
  +show(): void
}

class StringDisplay {
  -string: String
  +getColumns(): int
  +getRows(): int
  +getRowText(row: int): String
}

abstract class Border {
  #display: Display
  +Border(display: Display)
}

class SideBorder {
  -borderChar: char
  +SideBorder(display: Display, ch: char)
  +getColumns(): int
  +getRows(): int
  +getRowText(row: int): String
}

class FullBorder {
  +FullBorder(display: Display)
  +getColumns(): int
  +getRows(): int
  +getRowText(row: int): String
  -makeLine(ch: char, count: int): void
}

StringDisplay --|> Display
Border --|> Display
SideBorder --|> Border
FullBorder --|> Border
@enduml
